public void testBase64ConstructorDefaultsToNoLineBreaks() throws Exception {
    Base64 base64 = new Base64();
    byte[] input = new byte[100];
    for (int i = 0; i < input.length; i++) {
        input[i] = (byte) i;
    }
    byte[] encoded = base64.encode(input);
    String encodedStr = new String(encoded, "UTF-8");
    assertFalse("Default Base64() should not add line breaks", encodedStr.contains("\r") || encodedStr.contains("\n"));
}

public void testBase64DefaultConstructorChunking() throws Exception {
    Base64 base64 = new Base64();
    byte[] input = new byte[150];
    Arrays.fill(input, (byte) 65);
    byte[] encoded = base64.encode(input);
    int lineBreakCount = 0;
    for (byte b : encoded) {
        if (b == '\r' || b == '\n') {
            lineBreakCount++;
        }
    }
    assertEquals("Default Base64() should not chunk/add line separators", 0, lineBreakCount);
}
